class Solution {
public:
    int numberOfSubstrings(string s) {
        int count = 0;
        int n = s.length();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                for (int k = j + 1; k < n; k++) {
                    if (s[i] == s[j] && s[j] == s[k]) {
                        count += (n - i - j + 1);
                    }
                }
            }
        }
        return count;
    }
};
```

